import { INVENTORY_ENDPOINTS } from '../../../fixtures/api-endpoints.js'
const constants = require('../../../fixtures/app-constants.json')

const PRODUCT_LIST_URL = '/main/inventory/product-list'
const PRODUCT_LIST_API = INVENTORY_ENDPOINTS.PRODUCT_LIST
const PRODUCT_SUMMARY_API = INVENTORY_ENDPOINTS.PRODUCT_SUMMARY

// ---------------------------------------------------------------------------
// Stub factories
// ---------------------------------------------------------------------------

const stubProductList = (products = []) => {
  cy.intercept('GET', PRODUCT_LIST_API, {
    statusCode: 200,
    body: { success: true, data: products },
  }).as('productListApi')
}

const stubProductSummary = (data = {}) => {
  cy.intercept('GET', PRODUCT_SUMMARY_API, {
    statusCode: 200,
    body: {
      success: true,
      data: {
        totalProducts: 0,
        activeProducts: 0,
        inactiveProducts: 0,
        totalQuantity: 0,
        totalUsageQuantity: 0,
        favoriteProducts: 0,
        ...data,
      },
    },
  }).as('productSummaryApi')
}

// ---------------------------------------------------------------------------
// Sample products with distinct types — used to verify category is NOT shown
// ---------------------------------------------------------------------------

const hairCareProduct = {
  id: 1,
  uuid: 'test-uuid-1',
  brand: 'Dove',
  brand_id: 10,
  product: 'Shampoo',
  product_id: 20,
  type: 'Hair Care',
  product_status: 'active',
  quantity: 5,
  usage_quantity: 0,
  usage_date: '2026-04-01T00:00:00.000Z',
  is_favorite: false,
  deleted_at: null,
  note: '',
}

const skincareProduct = {
  id: 2,
  uuid: 'test-uuid-2',
  brand: 'Cetaphil',
  brand_id: 11,
  product: 'Moisturizer',
  product_id: 21,
  type: 'Skincare',
  product_status: 'active',
  quantity: 3,
  usage_quantity: 0,
  usage_date: '2026-03-01T00:00:00.000Z',
  is_favorite: false,
  deleted_at: null,
  note: '',
}

// ---------------------------------------------------------------------------
// A. Category section is NOT shown in filter dropdown (#37)
// ---------------------------------------------------------------------------

describe('Product Filter Dropdown — Category section removed (#37)', () => {
  beforeEach(() => {
    cy.setupApiAuthCookies()
    // Two products with different types — category section would have appeared before fix
    stubProductList([hairCareProduct, skincareProduct])
    stubProductSummary({ totalProducts: 2, activeProducts: 2 })

    cy.viewport(1280, 800)
    cy.visit(PRODUCT_LIST_URL)
    cy.wait('@productListApi')

    // Open the filter dropdown
    cy.contains('button', 'All Products').click()
  })

  it('does not render the Category label in the dropdown menu', () => {
    cy.get('[role="menu"]').should('be.visible')
    cy.get('[role="menu"]').contains('Category').should('not.exist')
  })

  it('does not render type-based menu items in the dropdown', () => {
    cy.get('[role="menu"]').should('be.visible')
    cy.get('[role="menu"]').contains('Hair Care').should('not.exist')
    cy.get('[role="menu"]').contains('Skincare').should('not.exist')
  })

  it('does not render the category separator in the dropdown', () => {
    // After #37: only Status / Inventory / Usage separators remain (3 total)
    // The category separator and its group are gone
    cy.get('[role="menu"]').within(() => {
      cy.get('[role="separator"]').should('have.length', 3)
    })
  })
})

// ---------------------------------------------------------------------------
// B. Standard filters still work after category removal (#37)
// ---------------------------------------------------------------------------

describe('Product Filter Dropdown — Standard filters unaffected after category removal', () => {
  beforeEach(() => {
    cy.setupApiAuthCookies()
    stubProductList([hairCareProduct, skincareProduct])
    stubProductSummary({ totalProducts: 2, activeProducts: 2 })

    cy.viewport(1280, 800)
    cy.visit(PRODUCT_LIST_URL)
    cy.wait('@productListApi')
  })

  it('filter dropdown opens and shows "All Products" as the default button label', () => {
    cy.contains('button', 'All Products').should('be.visible').click()
    cy.get('[role="menu"]').should('be.visible')
  })

  it('Active filter option is still present in the dropdown', () => {
    cy.contains('button', 'All Products').click()
    cy.get('[role="menu"]').contains('Active').should('be.visible')
  })

  it('Inactive filter option is still present in the dropdown', () => {
    cy.contains('button', 'All Products').click()
    cy.get('[role="menu"]').contains('Inactive').should('be.visible')
  })

  it('Low Stock filter option is still present in the dropdown', () => {
    cy.contains('button', 'All Products').click()
    cy.get('[role="menu"]').contains('Low Stock').should('be.visible')
  })

  it('Out of Stock filter option is still present in the dropdown', () => {
    cy.contains('button', 'All Products').click()
    cy.get('[role="menu"]').contains('Out of Stock').should('be.visible')
  })
})

// ---------------------------------------------------------------------------
// C. Filter button label does NOT show "type:" prefix values (#37)
// ---------------------------------------------------------------------------

describe('Product Filter Dropdown — No "type:" label in button (#37)', () => {
  it('filter button label cannot show a type: prefix value after selecting a standard filter', () => {
    cy.setupApiAuthCookies()
    stubProductList([hairCareProduct])
    stubProductSummary({ totalProducts: 1, activeProducts: 1 })

    cy.viewport(1280, 800)
    cy.visit(PRODUCT_LIST_URL)
    cy.wait('@productListApi')

    // Click "Active" filter
    cy.contains('button', 'All Products').click()
    cy.get('[role="menu"]').contains('Active').click()

    // Button label should say "Active", never "type:..."
    cy.contains('button', 'Active').should('be.visible')
    cy.contains('button', /type:/).should('not.exist')
  })
})
